INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_3172323','Що то за Пані?',NULL,'uk','ukraine_1991',NULL,NULL,'Господь - моя пісня: Збірник релігійних пісень. - Львів: Свідчадо, 2005. - 656 с.',NULL,'Що то за Пані
Ген за облаками,
Що до свого Сина
Мольби шле за нами?
Чи то не Марія,   |
Чи не Божа Мати   |
В блакитних ризах |
Повна благодати?  | (2)

Що то за Пані
Стоїть з ангелами?
Місяць і зорі
В Неї під ногами.
Чи то не Марія,   |
Чи не Божа Мати   |
В блакитних ризах |
Повна благодати?  | (2)

Чи то не та Пані,
Та Матір небесна,
Що на Голготу
Хрест за Сином несла?
Чи то не Марія,   |
Чи не Божа Мати   |
В блакитних ризах |
Повна благодати?  | (2)

Чи то не та Пані
На горі стояла,
Чи то не та Пані
В Крехові сіяла?
Чи то не Марія,   |
Чи не Божа Мати   |
В блакитних ризах |
Повна благодати?  | (2)

Чи то не та Пані,
Та ясна зірниця,
То Діва Марія
І небес Цариця.
Чи то не Марія,   |
Чи не Божа Мати   |
В блакитних ризах |
Повна благодати?  | (2)

Ах, то Марія,
Ах, то Божа Мати
В блакитних ризах
Повна благодати.
Чи то не Марія,   |
Чи не Божа Мати   |
В блакитних ризах |
Повна благодати?  | (2)','["pisni.org.ua", "cat:cerkovni", "cat:do-bohorodyci", "Церковні пісні", "Пісні до Богородиці"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_3172323'), datetime('now')),datetime('now'));
